using System.Text.Json;
using System.Text.Json.Serialization;
using System.Text.Json.Serialization.Metadata;

// --- 1. GetTypeInfo<T>(): strongly-typed metadata retrieval ---
var options = new JsonSerializerOptions(JsonSerializerDefaults.Web);

JsonTypeInfo<Person> personInfo = options.GetTypeInfo<Person>();
Console.WriteLine($"GetTypeInfo<Person> => Type = {personInfo.Type.Name}");

string json = JsonSerializer.Serialize(new Person("Ada", 38), personInfo);
Console.WriteLine($"Serialized: {json}");

// --- 2. TryGetTypeInfo<T>(): probe without throwing ---

// 2a. With the default (reflection-based) resolver, Person resolves fine:
if (options.TryGetTypeInfo<Person>(out JsonTypeInfo<Person>? found))
    Console.WriteLine($"TryGetTypeInfo<Person> => found ({found!.Type.Name})");
else
    Console.WriteLine("TryGetTypeInfo<Person> => NOT found");

// 2b. Build options that only know about Person via source-gen.
//     Widget is intentionally NOT in the context, so TryGetTypeInfo returns false.
var limited = new JsonSerializerOptions
{
    TypeInfoResolver = PersonOnlyContext.Default
};

if (limited.TryGetTypeInfo<Widget>(out JsonTypeInfo<Widget>? widgetInfo))
    Console.WriteLine($"TryGetTypeInfo<Widget> => found ({widgetInfo!.Type.Name})");
else
    Console.WriteLine("TryGetTypeInfo<Widget> => NOT found (as expected)");

// --- Types ---
public record Person(string Name, int Age);
public record Widget(int Id, string Label);

// Source-gen context that only includes Person
[JsonSerializable(typeof(Person))]
public partial class PersonOnlyContext : JsonSerializerContext;

